import type { AppSnapshot, PersistedState, Preferences, SiteSessionState, UsageEvent } from '../types';

export type RuntimeRequest =
  | { type: 'capture-session'; payload: SiteSessionState }
  | { type: 'commit-usage-event'; payload: UsageEvent }
  | { type: 'get-snapshot'; activeUrl?: string }
  | { type: 'get-state' }
  | { type: 'save-preferences'; payload: Preferences }
  | { type: 'export-data' }
  | { type: 'import-data'; payload: PersistedState }
  | { type: 'toggle-overlay'; value?: boolean }
  | { type: 'notify'; title: string; message: string };

export async function sendRuntimeMessage<T>(message: RuntimeRequest): Promise<T> {
  return chrome.runtime.sendMessage(message) as Promise<T>;
}

export async function getActiveTab(): Promise<any | undefined> {
  const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });
  return tab;
}

export async function getActiveUrl(): Promise<string | undefined> {
  const tab = await getActiveTab();
  return tab?.url;
}

export async function sendToActiveTab<T>(message: unknown): Promise<T | undefined> {
  const tab = await getActiveTab();
  if (!tab?.id) return undefined;
  try {
    return (await chrome.tabs.sendMessage(tab.id, message)) as T;
  } catch {
    return undefined;
  }
}

export type SnapshotResponse = AppSnapshot;
