import { SITE_LABELS } from '../lib/constants';
import { formatClock, formatCurrency, formatPercent, formatTokens } from '../lib/format';
import { getActiveUrl, sendRuntimeMessage, sendToActiveTab } from '../lib/runtime';
import type { AppSnapshot, SiteSessionState } from '../types';
import { truncate } from '../lib/utils';
import { renderBarList, renderSparkline } from '../ui/charts';

const usageCard = document.querySelector<HTMLElement>('#usage-card')!;
const trendChart = document.querySelector<HTMLElement>('#trend-chart')!;
const modelBreakdown = document.querySelector<HTMLElement>('#model-breakdown')!;
const suggestions = document.querySelector<HTMLElement>('#suggestions')!;
const changeSummary = document.querySelector<HTMLElement>('#change-summary')!;

function buildSessionSummary(session?: SiteSessionState, snapshot?: AppSnapshot): string {
  if (!session || !snapshot) {
    return 'Open ChatGPT, Claude, Gemini, Perplexity, or Grok to start capturing live token usage.';
  }
  const previous = snapshot.analytics.timeline[1];
  if (!previous) {
    return `Watching ${SITE_LABELS[session.site]} with ${session.model}. Your first captured exchange will appear here.`;
  }
  const delta = session.currentEstimate.inputTokens - previous.promptTokens;
  const direction = delta >= 0 ? 'larger' : 'smaller';
  return `The active prompt is ${formatTokens(Math.abs(delta))} tokens ${direction} than the previous captured exchange, and the current thread is around ${formatTokens(session.currentThread?.totalTokens)} tokens.`;
}

function renderHero(snapshot: AppSnapshot): void {
  const session = snapshot.currentSession;
  const percent = session?.quota.percentUsed ?? 0;
  const statusLabel = session?.quota.status === 'limited'
    ? 'Limit reached'
    : session?.quota.status === 'warning'
      ? 'Near limit'
      : session?.quota.accuracy === 'exact'
        ? 'Exact'
        : 'Estimated';

  usageCard.innerHTML = `
    <div class="hero-copy">
      <div>
        <h2>${session ? `${SITE_LABELS[session.site]} • ${session.model}` : 'No active AI tab'}</h2>
        <p>${session ? `Reset ${session.quota.nextReset?.localLabel ?? 'unknown'} • last update ${formatClock(session.lastUpdated)}` : 'Pin the popup while you work to monitor usage in real time.'}</p>
      </div>
      <span class="status-chip">${statusLabel}</span>
    </div>
    <div class="metric-grid">
      <div class="metric"><strong>${formatTokens(snapshot.summary.tokensToday)}</strong><span>today</span></div>
      <div class="metric"><strong>${formatTokens(snapshot.summary.tokensThisWeek)}</strong><span>7-day total</span></div>
      <div class="metric"><strong>${session ? formatTokens(session.currentEstimate.inputTokens) : '—'}</strong><span>current prompt</span></div>
      <div class="metric"><strong>${formatCurrency(snapshot.summary.costThisWeek)}</strong><span>est. cost</span></div>
    </div>
    <div class="meter-track"><span style="width:${Math.max(4, Math.min(percent, 100))}%"></span></div>
    <div class="metric-grid" style="margin-top:12px;">
      <div class="metric"><strong>${session ? formatPercent(session.quota.percentUsed) : '—'}</strong><span>quota used</span></div>
      <div class="metric"><strong>${session ? formatTokens(session.quota.remainingTokens) : '—'}</strong><span>remaining</span></div>
      <div class="metric"><strong>${session ? formatTokens(session.currentThread?.totalTokens) : '—'}</strong><span>thread total</span></div>
      <div class="metric"><strong>${session ? `${session.currentEstimate.compressionScore}%` : '—'}</strong><span>save potential</span></div>
    </div>
  `;
}

async function render(): Promise<void> {
  const activeUrl = await getActiveUrl();
  const snapshot = await sendRuntimeMessage<AppSnapshot>({ type: 'get-snapshot', activeUrl });
  renderHero(snapshot);
  renderSparkline(
    trendChart,
    snapshot.analytics.byDay.map((day) => day.tokens),
    snapshot.analytics.byDay.map((day) => day.date)
  );
  renderBarList(
    modelBreakdown,
    snapshot.analytics.byModel.slice(0, 4).map((item) => ({ label: item.label, value: item.tokens, meta: `${formatTokens(item.tokens)} • ${item.prompts} prompts` }))
  );

  const currentSuggestions = snapshot.currentSession?.currentEstimate.suggestions ?? [];
  suggestions.innerHTML = currentSuggestions.length
    ? currentSuggestions
        .slice(0, 3)
        .map(
          (item) => `
            <div class="suggestion-card">
              <strong>${item.title}</strong>
              <p>${item.description} Save about ${formatTokens(item.estimatedSavings)} tokens.</p>
            </div>
          `
        )
        .join('')
    : '<div class="empty-chart">No optimization warnings right now.</div>';

  changeSummary.textContent = buildSessionSummary(snapshot.currentSession, snapshot);

  document.querySelector<HTMLButtonElement>('#copy-summary-btn')!.onclick = async () => {
    const session = snapshot.currentSession;
    const summary = session
      ? `${SITE_LABELS[session.site]} • ${session.model}\nCurrent prompt: ${formatTokens(session.currentEstimate.inputTokens)}\nThread total: ${formatTokens(session.currentThread?.totalTokens)}\nQuota used: ${formatPercent(session.quota.percentUsed)}\nReset: ${session.quota.nextReset?.localLabel ?? 'unknown'}`
      : 'No active AI session yet.';
    await navigator.clipboard.writeText(summary);
  };

  document.querySelector<HTMLButtonElement>('#copy-shorter-btn')!.onclick = async () => {
    const shorter = snapshot.currentSession?.currentEstimate.variants.shorter;
    await navigator.clipboard.writeText(shorter || snapshot.currentSession?.currentInput || '');
  };

  document.querySelector<HTMLButtonElement>('#dashboard-btn')!.onclick = async () => {
    await chrome.tabs.create({ url: chrome.runtime.getURL('dashboard/dashboard.html') });
  };

  document.querySelector<HTMLButtonElement>('#settings-btn')!.onclick = async () => {
    await chrome.runtime.openOptionsPage();
  };

  document.querySelector<HTMLButtonElement>('#toggle-overlay-btn')!.onclick = async () => {
    await sendToActiveTab({ type: 'toggle-overlay' });
  };

  document.querySelector<HTMLButtonElement>('#refresh-btn')!.onclick = async () => {
    await sendToActiveTab({ type: 'refresh-session' });
    await render();
  };
}

void render();
