import { formatTokens } from '../lib/format';

export function renderSparkline(container: HTMLElement, values: number[], labels: string[] = []): void {
  if (!values.length) {
    container.innerHTML = '<div class="empty-chart">No usage data yet.</div>';
    return;
  }

  const width = 320;
  const height = 120;
  const max = Math.max(...values, 1);
  const min = Math.min(...values, 0);
  const range = Math.max(1, max - min);
  const points = values.map((value, index) => {
    const x = (index / Math.max(1, values.length - 1)) * width;
    const y = height - ((value - min) / range) * (height - 14) - 7;
    return `${x},${y}`;
  });

  const last = values.at(-1) ?? 0;
  container.innerHTML = `
    <div class="chart-meta"><strong>${formatTokens(last)}</strong><span>latest</span></div>
    <svg viewBox="0 0 ${width} ${height}" class="sparkline" role="img" aria-label="Usage sparkline">
      <defs>
        <linearGradient id="spark-fill" x1="0" x2="0" y1="0" y2="1">
          <stop offset="0%" stop-color="rgba(112, 240, 203, 0.38)"></stop>
          <stop offset="100%" stop-color="rgba(112, 240, 203, 0)"></stop>
        </linearGradient>
      </defs>
      <polyline fill="none" stroke="rgba(112,240,203,0.95)" stroke-width="3" points="${points.join(' ')}"></polyline>
      <polygon fill="url(#spark-fill)" points="0,${height} ${points.join(' ')} ${width},${height}"></polygon>
      ${values
        .map((value, index) => {
          const [x, y] = points[index].split(',');
          const label = labels[index] ?? `${index + 1}`;
          return `<circle cx="${x}" cy="${y}" r="3.4" fill="rgba(255,255,255,0.96)"><title>${label}: ${formatTokens(value)} tokens</title></circle>`;
        })
        .join('')}
    </svg>
  `;
}

export function renderBarList(
  container: HTMLElement,
  items: Array<{ label: string; value: number; meta?: string }>,
  formatter: (value: number) => string = formatTokens
): void {
  if (!items.length) {
    container.innerHTML = '<div class="empty-chart">Nothing captured yet.</div>';
    return;
  }
  const max = Math.max(...items.map((item) => item.value), 1);
  container.innerHTML = items
    .map(
      (item) => `
        <div class="bar-row">
          <div class="bar-copy">
            <strong>${item.label}</strong>
            <span>${item.meta ?? formatter(item.value)}</span>
          </div>
          <div class="bar-track"><span style="width:${Math.max(5, (item.value / max) * 100)}%"></span></div>
        </div>
      `
    )
    .join('');
}
